-- Semeia 40 veículos usados (com fotos) em 4 contas fictícias de revenda.
-- Idempotente: usa UUIDs/e-mails fixos com ON CONFLICT DO NOTHING.
-- As contas são premium (cota de anúncios ilimitada). Todos os anúncios
-- entram como 'active' e abaixo do teto de 85% da FIPE.
--
-- As fotos ficam no bucket público `listing-photos` (mesmo padrão dos demais
-- anúncios). O upload dos arquivos é feito à parte (ver observação ao final);
-- aqui registramos apenas os caminhos em listing_photos.
--
-- Os arquivos de foto ficam em `{owner_id}/seed-NN.jpg` no bucket
-- `listing-photos`. A migration não consegue subir binários; se o storage for
-- zerado, reenvie as imagens para esses caminhos (uma foto por anúncio).

-- 1) Contas de autenticação das revendas (senha: catirapp123)
-- As colunas *_token vão como '' (string vazia): o GoTrue não aceita NULL nelas
-- e o login por senha falha (HTTP 500) se ficarem nulas.
  instance_id, id, aud, role, email, encrypted_password,
  email_confirmed_at, created_at, updated_at,
  raw_app_meta_data, raw_user_meta_data,
  confirmation_token, recovery_token, email_change,
  email_change_token_new, email_change_token_current,
  phone_change, phone_change_token, reauthentication_token
)
values
  ('00000000-0000-0000-0000-000000000000', 'e0000000-0000-4000-8000-000000000001', 'authenticated', 'authenticated',
   'revenda1@catirapp.demo', crypt('catirapp123', gen_salt('bf')), now(), now(), now(),
   '{"provider":"email","providers":["email"]}'::jsonb, jsonb_build_object('display_name', 'Garagem Central Seminovos', 'city', 'Goiânia', 'state', 'GO'),
   '', '', '', '', '', '', '', ''),
  ('00000000-0000-0000-0000-000000000000', 'e0000000-0000-4000-8000-000000000002', 'authenticated', 'authenticated',
   'revenda2@catirapp.demo', crypt('catirapp123', gen_salt('bf')), now(), now(), now(),
   '{"provider":"email","providers":["email"]}'::jsonb, jsonb_build_object('display_name', 'Cerrado Motors', 'city', 'Brasília', 'state', 'DF'),
   '', '', '', '', '', '', '', ''),
  ('00000000-0000-0000-0000-000000000000', 'e0000000-0000-4000-8000-000000000003', 'authenticated', 'authenticated',
   'revenda3@catirapp.demo', crypt('catirapp123', gen_salt('bf')), now(), now(), now(),
   '{"provider":"email","providers":["email"]}'::jsonb, jsonb_build_object('display_name', 'Triângulo Veículos', 'city', 'Uberlândia', 'state', 'MG'),
   '', '', '', '', '', '', '', ''),
  ('00000000-0000-0000-0000-000000000000', 'e0000000-0000-4000-8000-000000000004', 'authenticated', 'authenticated',
   'revenda4@catirapp.demo', crypt('catirapp123', gen_salt('bf')), now(), now(), now(),
   '{"provider":"email","providers":["email"]}'::jsonb, jsonb_build_object('display_name', 'Rota Sul Automóveis', 'city', 'Rio Verde', 'state', 'GO'),
   '', '', '', '', '', '', '', '')
on conflict (id) do nothing;

-- 2) Identidade de e-mail (necessária para o login por senha)
  id, user_id, provider_id, identity_data, provider, last_sign_in_at, created_at, updated_at
)
values
  (gen_random_uuid(), 'e0000000-0000-4000-8000-000000000001', 'e0000000-0000-4000-8000-000000000001', jsonb_build_object('sub', 'e0000000-0000-4000-8000-000000000001', 'email', 'revenda1@catirapp.demo', 'email_verified', true, 'phone_verified', false), 'email', now(), now(), now()),
  (gen_random_uuid(), 'e0000000-0000-4000-8000-000000000002', 'e0000000-0000-4000-8000-000000000002', jsonb_build_object('sub', 'e0000000-0000-4000-8000-000000000002', 'email', 'revenda2@catirapp.demo', 'email_verified', true, 'phone_verified', false), 'email', now(), now(), now()),
  (gen_random_uuid(), 'e0000000-0000-4000-8000-000000000003', 'e0000000-0000-4000-8000-000000000003', jsonb_build_object('sub', 'e0000000-0000-4000-8000-000000000003', 'email', 'revenda3@catirapp.demo', 'email_verified', true, 'phone_verified', false), 'email', now(), now(), now()),
  (gen_random_uuid(), 'e0000000-0000-4000-8000-000000000004', 'e0000000-0000-4000-8000-000000000004', jsonb_build_object('sub', 'e0000000-0000-4000-8000-000000000004', 'email', 'revenda4@catirapp.demo', 'email_verified', true, 'phone_verified', false), 'email', now(), now(), now())
on conflict do nothing;

-- 3) Perfis premium (o trigger cria o perfil como free; ajustamos plano/telefone)
update profiles set plan_code = 'premium', phone = '(62) 99911-0001', display_name = 'Garagem Central Seminovos', city = 'Goiânia', state = 'GO' where id = 'e0000000-0000-4000-8000-000000000001';
update profiles set plan_code = 'premium', phone = '(61) 99911-0002', display_name = 'Cerrado Motors', city = 'Brasília', state = 'DF' where id = 'e0000000-0000-4000-8000-000000000002';
update profiles set plan_code = 'premium', phone = '(34) 99911-0003', display_name = 'Triângulo Veículos', city = 'Uberlândia', state = 'MG' where id = 'e0000000-0000-4000-8000-000000000003';
update profiles set plan_code = 'premium', phone = '(64) 99911-0004', display_name = 'Rota Sul Automóveis', city = 'Rio Verde', state = 'GO' where id = 'e0000000-0000-4000-8000-000000000004';

-- 4) Bens da garagem (assets) que lastreiam cada anúncio
on conflict (id) do nothing;

